import sailpoint.object.ProvisioningPlan;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import org.apache.log4j.Logger;

Logger logger = Logger.getLogger("sailpoint.ascension.rules.gsuite.initilizeattributes");

logger.trace("Entering GSuite AfterProvision Workflow");
logger.trace("Begin Initialization Step");

ProvisioningPlan plan = new ProvisioningPlan();

plan.setNativeIdentity(identityName);

logger.trace(plan.toXml());

return plan;

import sailpoint.api.Provisioner;
import org.apache.log4j.Logger;

Logger logger = Logger.getLogger("sailpoint.ascension.rules.gsuite.initilizeattributes");

logger.trace("Begin Provision Step");

Provisioner provisioner = new Provisioner(context);

logger.trace(plan.toXml());

provisioner.execute(plan);

import sailpoint.object.Application;
import sailpoint.object.Attributes;
import sailpoint.object.AuditEvent;
import sailpoint.server.Auditor;
import sailpoint.object.Identity;
import org.apache.log4j.Logger;

Logger logger = Logger.getLogger("sailpoint.ascension.rules.gsuite.initilizeattributes");

//Initialize Variables

Identity refIdentity = context.getObjectByName(Identity.class, identityName);
Application refApp = context.getObjectByName(Application.class, targetApp);

List conflictList = new ArrayList();

logger.trace("Begin Prep Plan Step");

// Build AccountRequest 

accountReq = new AccountRequest();

accountReq.setOperation(AccountRequest.Operation.Modify);
accountReq.setNativeIdentity(targetDN);
accountReq.setApplication(targetApp);

// Supplemental Account Request to Update email, gsuiteStatus, and orgUnitPath

AccountRequest accountReqTwo = new AccountRequest();
accountReqTwo.setOperation(AccountRequest.Operation.Modify);
accountReqTwo.setNativeIdentity(identityName);
accountReqTwo.setApplication("IIQ");

// Build AttributeRequests

buildAttrReq("msExchExtensionAttribute40", ea40, accountReq);

buildAttrReq("extensionAttribute6", ea6, accountReq);

buildAttrReq("mail", primaryEmail, accountReq);

buildAttrReq("msExchRecipientTypeDetails", "128", accountReq);

buildAttrReq("msExchRecipientDisplayType", "6", accountReq);

Attributes attrMap = new Attributes();

attrMap.put("msExchExtensionAttribute40", ea40);
attrMap.put("extensionAttribute6", ea6);
attrMap.put("mail", primaryEmail);
attrMap.put("msExchRecipientTypeDetails", "128");
attrMap.put("msExchRecipientDisplayType", "6");
attrMap.put("mailNickname", samAccountName);
attrMap.put("userPrincipalName", primaryEmail);
attrMap.put("IIQ-email", primaryEmail);
attrMap.put("IIQ-gsuiteStatus", ea40);
attrMap.put("IIQ-orgUnitPath", orgUnitPath);

if (targetConflict) {

   attrMap.put("targetConflict", targetConflict);

}
String targetUpnQueryResult = queryCheckUpnArs(primaryEmail);
if (Util.nullSafeCaseInsensitiveEq(targetUpnQueryResult, "PotentialUPNConflict")) {
   attrMap.put("upnConflict", "true");
   wfcontext.setVariable("upnConflict", true);
}
String proxyAddressQueryResult = "";
List proxyAddressList = buildProxyAddressList(refIdentity, prefix, suffix);
List toRemove = new ArrayList();

  for (String intendedProxyAddress : proxyAddressList) {

    proxyAddressQueryResult = queryARSForProxyAddressConflict(primaryEmail);

    if (Util.nullSafeCaseInsensitiveEq(proxyAddressQueryResult, "ProxyAddressConflict")) {

      conflictList.add("proxyAddresses" + "=" + "\"" + intendedProxyAddress + "\"");
      toRemove.add(intendedProxyAddress);

    }

  }

  if (proxyAddressList != null && proxyAddressList.size() > 0) {

    if (toRemove != null && toRemove.size() > 0) {

      proxyAddressList.removeAll(toRemove);

    }

  }

  if (proxyAddressList != null && proxyAddressList.size() > 0) {

    buildAttrReq("proxyAddresses", proxyAddressList, accountReq);

    attrMap.put("proxyAddresses", proxyAddressList);

  }

String targetAddressQueryResult = queryARSForTargetAddressConflict(primaryEmail);
String intendedTargetAddress = buildTargetAddress(refIdentity, prefix, suffix);

  if (Util.nullSafeCaseInsensitiveEq(targetAddressQueryResult, "ObjectDoesNotExist")) {

    buildAttrReq("targetAddress", intendedTargetAddress, accountReq);

    attrMap.put("targetAddress", intendedTargetAddress);

  } else if (Util.nullSafeCaseInsensitiveEq(targetAddressQueryResult, "TargetAddressConflict")) {

    conflictList.add("targetAddress" + "=" + "\"" + intendedTargetAddress + "\"");

  }

buildAttrReq("mailNickname", samAccountName, accountReq);

buildAttrReq("userPrincipalName", primaryEmail, accountReq);

buildAttrReq("email", primaryEmail, accountReqTwo);
buildAttrReq("gsuiteStatus", ea40, accountReqTwo);
buildAttrReq("orgUnitPath", orgUnitPath, accountReqTwo);

// Handle Conflicts

if (conflictList != null && conflictList.size() > 0) {

  //buildAfterProvisioningWorkItem(refIdentity, refApp, targetDN, conflictList);

  attrMap.put("hadConflict", "true");

}

// Record Plan via AuditEvent

AuditEvent auditEvent = new AuditEvent();

auditEvent = new AuditEvent("GSuite-AfterProvisioning-Plan", "Comment", identityName);
auditEvent.setApplication(targetApp);
auditEvent.setAccountName(targetDN);
auditEvent.setString1("GSuite Link Provisioned for: " + identityName);
auditEvent.setString2("AfterProvisioning Plan Record");
auditEvent.setString3("Target samAccountName: " + samAccountName);
auditEvent.setString4("Note: If record includes hadConflict (i.e targetAddress or proxyAddress conflict) there would have been a WorkItem generated for those. Note 2: If record includes targetConflict or upnConflict, AfterProvisioning never occured (see the related TaskResult).");
auditEvent.setAttributes(attrMap);
Auditor.log(auditEvent);
context.commitTransaction();

// Finalize Plan

List accountReqList = new ArrayList();

accountReqList.add(accountReq);
accountReqList.add(accountReqTwo);
plan.setAccountRequests(accountReqList);
plan.setIdentity(refIdentity);

//context.decache(refIdentity);
//context.decache(refApp);

return plan;
